7	#include <uhd/cal/database.hpp>
8	#include <uhd/exception.hpp>
9	#include <uhd/utils/paths.hpp>
10	#include <stdlib.h> // putenv or _putenv
11	#include <boost/test/unit_test.hpp>
12	#include <filesystem>
13	#include <iostream>
14	#include <numeric>
15	
16	using namespace uhd::usrp::cal;
17	namespace fs = std::filesystem;
18	
19	BOOST_AUTO_TEST_CASE(test_rc)
20	{
21	    BOOST_CHECK(!database::has_cal_data("does_not_exist", "1234", source::RC));
22	    BOOST_CHECK(database::has_cal_data("test", "1234", source::RC));
23	    BOOST_CHECK(database::has_cal_data("test", "1234"));
24	    BOOST_CHECK(!database::has_cal_data("test", "1234", source::FILESYSTEM));
25	
26	    const auto test_data = database::read_cal_data("test", "", source::RC);
27	    const std::string test_str(test_data.cbegin(), test_data.cend());
28	    // The expected string is also in the test.cal file. We could, in this test,
29	    // open that file and dynamically generate the expected data, but let's not.
30	    // First, that adds complexity here, and second, both test.cal and this test
31	    // are hashed with the same git commit, and thus we also test the integrity
32	    // of test.cal.
33	    BOOST_CHECK_EQUAL(test_str, "rc::cal::test_data");
34	}
35	
36	BOOST_AUTO_TEST_CASE(test_fs)
37	{
38	    BOOST_CHECK(!database::has_cal_data("does_not_exist", "1234", source::FILESYSTEM));
39	
40	    const auto tmp_dir      = uhd::get_tmp_path();
41	    const auto tmp_cal_path = fs::path(tmp_dir) / "CAL_TEST";
42	    std::error_code ec;
43	    fs::create_directory(tmp_cal_path, ec);
44	    if (ec) {
45	        std::cout << "WARNING: Could not create temp cal path. Skipping test."
46	                  << std::endl;
47	        return;
48	    }
49	    std::cout << "Using temporary cal path: " << tmp_cal_path << std::endl;
50	
51	    // Now we do a non-portable hack to override the cal path during runtime:
52	#ifdef UHD_PLATFORM_WIN32
53	    const std::string putenv_str =
54	        std::string("UHD_CAL_DATA_PATH=") + tmp_cal_path.string();
55	    _putenv(putenv_str.c_str());
56	#else
57	    setenv("UHD_CAL_DATA_PATH", tmp_cal_path.string().c_str(), /* overwrite */ 1);
58	#endif
59	
60	    // Because of the hack, we won't fail if it didn't work, but instead, print
61	    // a warning and exit this test. Running the following lines requires the
62	    // hack to succeed.
63	    if (uhd::get_cal_data_path() != tmp_cal_path) {
64	        std::cout << "WARNING: Unable to update UHD_CAL_DATA_PATH! get_cal_data_path(): "
65	                  << uhd::get_cal_data_path() << std::endl;
66	        return;
67	    }
68	
69	    std::vector<uint8_t> mock_data{1, 2, 3, 4, 5};
70	    database::write_cal_data("mock_data", "1234", mock_data);
71	    auto mock_data_rb = database::read_cal_data("mock_data", "1234");
72	    BOOST_CHECK_EQUAL_COLLECTIONS(
73	        mock_data.begin(), mock_data.end(), mock_data_rb.begin(), mock_data_rb.end());
74	
75	    BOOST_CHECK(!database::has_cal_data("mock_data", "abcd"));
76	    std::vector<uint8_t> mock_data2{2, 3, 4, 5, 6};
77	    database::write_cal_data("mock_data", "abcd", mock_data);
78	    // Write it twice to force a backup
79	    database::write_cal_data("mock_data", "abcd", mock_data2, "BACKUP");
80	    mock_data_rb = database::read_cal_data("mock_data", "abcd");
81	    BOOST_CHECK_EQUAL_COLLECTIONS(
82	        mock_data2.begin(), mock_data2.end(), mock_data_rb.begin(), mock_data_rb.end());
83	    BOOST_CHECK(database::has_cal_data("mock_data", "abcd"));
84	    BOOST_CHECK(fs::exists(tmp_cal_path / "mock_data_abcd.cal.BACKUP"));
85	
86	    fs::remove_all(tmp_cal_path, ec);
87	    if (ec) {
88	        std::cout << "WARNING: Could not remove temp cal path." << std::endl;
89	    }
90	}
