92	BOOST_AUTO_TEST_CASE(test_flash)
93	{
94	    // 4 bytes of cal data
95	    std::vector<uint8_t> mock_cal_data{42, 23, 1, 2};
96	
97	    database::register_lookup(
98	        [&](const std::string& key, const std::string&) {
99	            // Note: We're deliberately not checking the key here, but below, so
100	            // we can check all code paths in database.cpp, even the ones we're
101	            // not supposed to reach
102	            return key == "MOCK_KEY";
103	        },
104	        [&](const std::string& key, const std::string& serial) {
105	            if (key == "MOCK_KEY" && serial == "MOCK_SERIAL") {
106	                return mock_cal_data;
107	            }
108	            throw uhd::runtime_error("no such mock data!");
109	        });
